const GDA_CAPS=['training','simulation','seta','c5isr','cyber','intelligence','analytics','modeling','systems engineering','software','digital','ai','machine learning'];
const ckw=['rs3','oasis','cio-sp','shield','maps','stri','iews','seta','tradoc','socom','army','disa','cyber'];
const items=$input.all();
if(!items||items.length===0||!items[0].json.id){
  return [{json:{batchSql:'SELECT 1',count:0,summary:[]}}];
}
const scored=[];
for(const item of items){
  const c=item.json;
  if(!c.id)continue;
  let score=0,factors=[];
  const caps=(c.capabilities||'').toLowerCase();
  const kc=(c.known_contracts||'').toLowerCase();
  let ch=0;
  for(const cap of GDA_CAPS){if(caps.includes(cap))ch++;}
  score+=Math.min(30,Math.round((ch/13)*30));
  if(ch>0)factors.push('Cap:'+ch);
  let cth=0;
  for(const kw of ckw){if(kc.includes(kw)||caps.includes(kw))cth++;}
  score+=Math.min(25,cth*4);
  if(cth>0)factors.push('Kw:'+cth);
  score+=15;
  score+=(c.weaknesses||'').length>20?10:5;
  score=Math.min(100,score);
  let tl=score>=65?'CRITICAL':score>=45?'HIGH':score>=25?'MEDIUM':'LOW';
  const sf=factors.join('; ').replace(/'/g,"''");
  scored.push({id:c.id,name:c.name,score,level:tl,factors:sf});
}
const sqls=scored.map(s=>`UPDATE gda_competitor_watchlist SET threat_score=${s.score},threat_level='${s.level}',scoring_factors='${s.factors}',scored_at=NOW() WHERE id=${s.id}`).join(';');
return [{json:{batchSql:sqls||'SELECT 1',count:scored.length,summary:scored}}];
